async function SetFavorite() {
  try {
    const sesion = localStorage.getItem("token")
    if (!sesion) return
    const currentAudio = audios.value[currentIndex.value]

    const response = await fetch(`${API_BASE_URL}/api/audioteca/SetAudioteca`, {
