//Reproducción
function setupVisualizer() {
  audioContext = new (window.AudioContext || window.webkitAudioContext)()
  analyser = audioContext.createAnalyser()
  analyser.fftSize = 256
  const bufferLength = analyser.frequencyBinCount
  dataArray = new Uint8Array(bufferLength)

  source = audioContext.createMediaElementSource(audio)
  source.connect(analyser)
  analyser.connect(audioContext.destination)

  drawVisualizer()

  if (audioContext.state === 'suspended') {
    const resume = () => {
      audioContext.resume()
      document.removeEventListener('touchstart', resume)
    }
    document.addEventListener('touchstart', resume, { once: true })
  }
}

function drawVisualizer() {
  const canvas = canvasRef.value
  const ctx = canvas.getContext('2d')
  const width = canvas.width
  const height = canvas.height
  const centerX = width / 2
  const centerY = height / 2

  analyser.fftSize = 512 // Resolución más pequeña capta bandas más anchas (más energía)

  let currentRadius = 40
  const baseRadius = 40
  const maxExpand = 58

  let baseline = 0;
  let currentFactorSmoothed = 0;

  function draw() {
    animationId = requestAnimationFrame(draw)
    analyser.getByteFrequencyData(dataArray)

    // 1. Ampliamos el rango de frecuencias graves para captar más cuerpo del sonido
    let sumLow = 0;
    const lowBins = 100;
    for (let i = 0; i < lowBins; i++) {
      sumLow += dataArray[i];
    }
    const currentLowIntensity = sumLow / lowBins;

    // 2. Línea base altamente responsiva (reacciona rápido al cambio del audio)
    baseline = (baseline * 0.90) + (currentLowIntensity * 0.10);

    // 3. Expansión constante multiplicada brutalmente para que el ambiente lo mueva
    // Multiplicamos por 2.5 la intensidad para que "cualquier cosita" lo haga vibrar
    const ambientExpansion = Math.min(1, (currentLowIntensity * 5) / 255) * (maxExpand * 0.6);

    // B) Expansión por pico (UDU): Threshold ultra bajo para que el mínimo acento dispare el verde
    let beatExpansion = 0;
    const threshold = 5 // Apenas asome una frecuencia, salta

    if (currentLowIntensity > baseline + threshold) {
      let beatIntensity = currentLowIntensity - baseline;
      // Multiplicador agresivo para que llene el canvas
      beatExpansion = Math.min(1, (beatIntensity * 6) / 255) * (maxExpand * 0.6);
    }

    const targetRadius = baseRadius + ambientExpansion + beatExpansion;

    // Mismo rebote suave
    const smoothingFactor = targetRadius > currentRadius ? 0.40 : 0.05;
    currentRadius += (targetRadius - currentRadius) * smoothingFactor;

    ctx.clearRect(0, 0, width, height)

    // 4. Color: Si el radio está al 5% de expandirse por el beat, ya empieza a ser verde
    const rawFactor = Math.min(1, Math.max(0, ((currentRadius - baseRadius) / maxExpand) * 1.5));
    currentFactorSmoothed += (rawFactor - currentFactorSmoothed) * 0.08;

    const r = Math.floor(0 + (50 * currentFactorSmoothed));
    const g = Math.floor(150 + (105 * currentFactorSmoothed));
    const b = Math.floor(255 - (205 * currentFactorSmoothed));

    const gradient = ctx.createRadialGradient(
      centerX, centerY, baseRadius * 0.5,
      centerX, centerY, currentRadius
    )

    gradient.addColorStop(0, `rgba(${r}, ${g}, ${b}, 0.8)`)
    gradient.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, 0.3)`)
    gradient.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`)

    ctx.beginPath()
    ctx.fillStyle = gradient
    ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
    ctx.fill()

    ctx.beginPath()
    ctx.lineWidth = 2
    ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${currentFactorSmoothed + 0.2})`
    ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2)
    ctx.stroke()
  }
  draw()
}


