function shuffleArray(length) {
  const indices = [...Array(length).keys()]
  for (let i = indices.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
      ;[indices[i], indices[j]] = [indices[j], indices[i]]
  }
  return indices
}
//----------------------------- Nueva reproducción 
//Inicia contador de audio en 0
function loadTrack(index) {
  const currentAudio = audios.value[index]
  audio.src = currentAudio.url

  // 👇 sincroniza el corazón según el valor de Estatus
  isFavorite.value = !!currentAudio.estatus
  durationSong.value = 0
  audio.load()
  stopPlaybackTimer()
  audio.play().then(() => {
    isPlaying.value = true
    startPlaybackTimer()
  }).catch(err => {
    console.warn('iOS puede haber bloqueado la reproducción:', err)
  })
}
//Pausa o play Manda a llamar play con valor 1 que se esta pausando el audio
function togglePlay() {
  if (audio.paused) {
    startPlaybackTimer()
    audio.play()
    isPlaying.value = true
  } else {
    SetPlay(1)
    stopPlaybackTimer()
    audio.pause()
    isPlaying.value = false
    countPause.value++;
    if (!hasShownMomentThisSession() && (playbackSeconds.value >= 15 | (playbackSeconds.value >= 14 && countPause.value > 1))) {
      moment.value = true;
      hasShownMessage.value = true
      playbackSeconds.value = 0
      countPause.value = 0
    }
  }
}



//No se que hace
function startPlaybackTimer() {
  if (playbackInterval) return // Evita múltiples intervalos

  playbackInterval = setInterval(() => {
    playbackSeconds.value++
    durationSong.value++
  }, 1000)
}
//No se que hace
function stopPlaybackTimer() {
  clearInterval(playbackInterval)
  playbackInterval = null
}
// Siguiente canción Llama a play con 0
function nextTrack() {
  SetPlay(0)
  if (isShuffle.value) {
    if (shuffledIndices.length === 0) {
      shuffledIndices = shuffleArray(audios.value.length)
    }
    currentIndex.value = shuffledIndices.shift()
  } else {
    currentIndex.value = (currentIndex.value + 1) % audios.value.length
  }
  loadTrack(currentIndex.value)
}
//Canción anterior llama a play con 0
function prevTrack() {
  SetPlay(0)
  if (isShuffle.value) {
    if (shuffledIndices.length === 0) {
      shuffledIndices = shuffleArray(audios.value.length)
    }
    currentIndex.value = shuffledIndices.shift()
  } else {
    currentIndex.value = (currentIndex.value - 1 + audios.value.length) % audios.value.length
  }
  loadTrack(currentIndex.value)
}
//No se que hace
function seekAudio() {
  audio.currentTime = currentTime.value
}

audio.addEventListener('timeupdate', () => {
  currentTime.value = audio.currentTime
  duration.value = audio.duration || 0
})

audio.addEventListener('ended', async () => {
  console.log("termina canción")
  // SetPlay(0)
  nextTrack()
})

//Formatea fecha
function formatTime(time) {
  const minutes = Math.floor(time / 60)
  const seconds = Math.floor(time % 60).toString().padStart(2, '0')
  return `${minutes}:${seconds}`
}
//Obtiene audios
async function GetAudios() {
  try {
    const sesion = localStorage.getItem("token")
    if (!sesion) return
    const response = await fetch(`${API_BASE_URL}/api/config/GetAudiosUser`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username: sesion })
    })

    if (!response.ok) throw new Error("Error en la petición")

    const data = await response.json()

    const dataAudios = Array.isArray(JSON.parse(data.data)) ? JSON.parse(data.data) : data.data
    if (!Array.isArray(dataAudios)) throw new Error("dataAudios no es un array")

    const arr = dataAudios.map(item => {
      const limpio = limpiarNombre(item.Nombre)
      return {
        id: item.Audio,
        url: `/audios/${limpio}`,
        estatus: item.Estatus ?? false, // 👈 guarda el valor de la API
        nombre: limpio.replace(/\.[^/.]+$/, "")
      }
    })

    audios.value = arr

    if (audios.value.length > 0) {
      loadTrack(0)
    }

  } catch (error) {
    console.error("Error al cargar audios:", error)
  }
}


