//Guarda momento
async function SetMoment() {
  try {
    const sesion = localStorage.getItem("token")
    if (!sesion) return

    const response = await fetch(`${API_BASE_URL}/api/config/SetMoment`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ idMomento: document.querySelector('input[name="plan"]:checked').value, idUser: sesion, idAudio: idPlay.value })
    })
    moment.value = false
    if (!response.ok) throw new Error("Error en la petición")

    markMomentAsShown()
    showMomentButton.value = false

  } catch (error) {
    console.error("Error al cargar audios:", error)
    moment.value = false
  }
}
